from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Find the main subject (politician)
    main_subject = None
    for subj in subject_triples:
        for t in subject_triples[subj]:
            if t.predicate in ["profession", "office", "party", "nationality", "birthPlace",
                              "deathPlace", "almaMater", "state", "country"]:
                main_subject = subj
                break
        if main_subject:
            break

    if not main_subject and subject_triples:
        main_subject = list(subject_triples.keys())[0]

    if not main_subject:
        return ""

    main_triples = subject_triples.get(main_subject, [])

    # Build sentence parts
    sentence_parts = []
    additional_info = []

    for t in main_triples:
        if t.predicate == "birthPlace":
            additional_info.append(f"born in {t.object}")
        elif t.predicate == "birthDate":
            additional_info.append(f"born on {t.object}")
        elif t.predicate == "birthYear":
            additional_info.append(f"born in {t.object}")
        elif t.predicate == "deathPlace":
            additional_info.append(f"died in {t.object}")
        elif t.predicate == "deathDate":
            additional_info.append(f"died on {t.object}")
        elif t.predicate == "deathYear":
            additional_info.append(f"died in {t.object}")
        elif t.predicate == "nationality":
            additional_info.append(f"{t.object} nationality")
        elif t.predicate == "almaMater":
            additional_info.append(f"educated at {t.object}")
        elif t.predicate == "spouse":
            additional_info.append(f"spouse {t.object}")
        elif t.predicate == "office":
            sentence_parts.append(f"held the office of {t.object}")
        elif t.predicate == "party":
            sentence_parts.append(f"member of the {t.object} party")
        elif t.predicate == "successor":
            additional_info.append(f"succeeded by {t.object}")
        elif t.predicate == "predecessor":
            additional_info.append(f"preceded by {t.object}")
        elif t.predicate == "inOfficeWhilePresident":
            additional_info.append(f"served while {t.object} was president")
        elif t.predicate == "inOfficeWhilePrimeMinister":
            additional_info.append(f"served while {t.object} was prime minister")
        elif t.predicate == "inOfficeWhileVicePresident":
            additional_info.append(f"served while {t.object} was vice president")
        elif t.predicate == "inOfficeWhileGovernor":
            additional_info.append(f"served while {t.object} was governor")
        elif t.predicate == "inOfficeWhileMonarch":
            additional_info.append(f"served while {t.object} was monarch")
        elif t.predicate == "religion":
            additional_info.append(f"of {t.object} faith")
        elif t.predicate == "profession":
            additional_info.append(f"{t.object}")
        elif t.predicate == "militaryBranch":
            additional_info.append(f"of {t.object}")
        elif t.predicate == "militaryRank":
            additional_info.append(f"rank {t.object}")
        elif t.predicate == "activeYearsStartDate":
            additional_info.append(f"active since {t.object}")
        elif t.predicate == "activeYearsEndDate":
            additional_info.append(f"active until {t.object}")
        elif t.predicate == "residence":
            additional_info.append(f"resided in {t.object}")
        elif t.predicate == "region":
            additional_info.append(f"from {t.object}")
        elif t.predicate == "state":
            additional_info.append(f"from {t.object}")
        elif t.predicate == "country":
            additional_info.append(f"from {t.object}")
        elif t.predicate == "award":
            additional_info.append(f"received {t.object}")
        elif t.predicate == "unit":
            additional_info.append(f"unit {t.object}")
        elif t.predicate == "hasDeputy":
            additional_info.append(f"deputy {t.object}")
        elif t.predicate == "serviceStartYear":
            additional_info.append(f"service began {t.object}")
        elif t.predicate == "numberOfVotesAttained":
            additional_info.append(f"attained {t.object} votes")

    # Handle related subject triples (country, capital, etc.)
    related_info = []
    for subj, subj_triples in subject_triples.items():
        if subj != main_subject:
            for t in subj_triples:
                if t.predicate == "capital":
                    related_info.append(f"capital {t.object}")
                elif t.predicate == "country":
                    related_info.append(f"country {t.object}")
                elif t.predicate == "leader":
                    related_info.append(f"leader {t.object}")
                elif t.predicate == "currency":
                    related_info.append(f"currency {t.object}")
                elif t.predicate == "language":
                    related_info.append(f"language {t.object}")
                elif t.predicate == "officialLanguage":
                    related_info.append(f"official language {t.object}")

    # Build the final sentence
    if sentence_parts and additional_info:
        result = f"{main_subject}, {' and '.join(additional_info)}, {' and '.join(sentence_parts)}"
    elif sentence_parts:
        result = f"{main_subject} {' and '.join(sentence_parts)}"
    elif additional_info:
        result = f"{main_subject} {' and '.join(additional_info)}"
    else:
        result = main_subject

    # Add related info if present
    if related_info:
        result += f" in {' and '.join(related_info)}"

    return result

# EVOLVE-BLOCK-END

